INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 126401, 2002, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 1.47, "クローチェ", "2023/06/30 12:00:00", 0.0, 1, 1, -470.0, 1, "2023/09/22 14:59:59", 10001);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 126401, 2002, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2.15, "クローチェ", "2023/06/30 12:00:00", 0.0, 2, 2, -470.0, 1, "2023/09/22 14:59:59", 10002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 126501, 2002, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, "ライラエル", "2023/06/30 12:00:00", 0.0, 1, 2, -470.0, 1, "2023/09/22 14:59:59", 10003);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 126501, 2002, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, "ライラエル", "2023/06/30 12:00:00", 0.0, 2, 1, -470.0, 1, "2023/09/22 14:59:59", 10004);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 127702, 2002, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, "リンド", "2023/09/15 15:00:00", 0.0, 1, 2, -470.0, 2, "2023/12/22 14:59:59", 10005);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 127702, 2002, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, "リンド", "2023/09/15 15:00:00", 0.0, 2, 2, -470.0, 2, "2023/12/22 14:59:59", 10006);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 127802, 2002, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, "ヴルム", "2023/09/15 15:00:00", 0.0, 1, 1, -470.0, 2, "2023/12/22 14:59:59", 10007);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 127802, 2002, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 6.5, "ヴルム", "2023/09/15 15:00:00", 0.0, 2, 2, -470.0, 2, "2023/12/22 14:59:59", 10008);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 129602, 2002, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, "アネモネ", "2023/12/15 15:00:00", 0.0, 1, 2, -470.0, 3, "2024/03/22 14:59:59", 10009);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 129602, 2002, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, "アネモネ", "2023/12/15 15:00:00", 0.0, 2, 2, -470.0, 3, "2024/03/22 14:59:59", 10010);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 129701, 2002, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, "ネフィ=ネラ", "2023/12/15 15:00:00", 0.0, 1, 1, -470.0, 3, "2024/03/22 14:59:59", 10011);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 129701, 2002, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 6.2, "ネフィ=ネラ", "2023/12/15 15:00:00", 0.0, 2, 2, -470.0, 3, "2024/03/22 14:59:59", 10012);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 130301, 2002, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 3.1, "カノン", "2024/03/15 15:00:00", 0.0, 1, 3, -470.0, 4, "2024/06/22 14:59:59", 10013);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 130301, 2002, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 6.15, "カノン", "2024/03/15 15:00:00", 0.0, 2, 3, -470.0, 4, "2024/06/22 14:59:59", 10014);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 130401, 2002, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, "ナーナ", "2024/03/15 15:00:00", 0.0, 1, 2, -470.0, 4, "2024/06/22 14:59:59", 10015);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 130401, 2002, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 3.35, "ナーナ", "2024/03/15 15:00:00", 0.0, 2, 2, -470.0, 4, "2024/06/22 14:59:59", 10016);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 130502, 2002, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, "ホウオウ", "2024/06/15 15:00:00", 0.0, 1, 1, -470.0, 5, "2024/09/22 14:59:59", 10017);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 130502, 2002, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 3.18, "ホウオウ", "2024/06/15 15:00:00", 0.0, 2, 2, -470.0, 5, "2024/09/22 14:59:59", 10018);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 130503, 2002, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, "ホウオウ", "2024/06/15 15:00:00", 0.0, 3, 4, -470.0, 5, "2024/09/22 14:59:59", 10019);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 123301, 2002, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 4.9, "ネア", "2024/06/15 15:00:00", 0.0, 1, 1, -470.0, 5, "2024/09/22 14:59:59", 10020);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 123301, 2002, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 4.8, "ネア", "2024/06/15 15:00:00", 0.0, 2, 1, -470.0, 5, "2024/09/22 14:59:59", 10021);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 133301, 2002, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 4.922, "カリザ", "2024/09/15 15:00:00", 0.0, 1, 3, -470.0, 6, "2024/12/22 14:59:59", 10022);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 133301, 2002, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 9.638, "カリザ", "2024/09/15 15:00:00", 0.0, 2, 3, -470.0, 6, "2024/12/22 14:59:59", 10023);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 133401, 2002, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2.88, "ミーア", "2024/09/15 15:00:00", 0.0, 1, 1, -470.0, 6, "2024/12/22 14:59:59", 10024);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 133401, 2002, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 4.818, "ミーア", "2024/09/15 15:00:00", 0.0, 2, 5, -470.0, 6, "2024/12/22 14:59:59", 10025);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 133002, 2002, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 1.78, "グレイス", "2024/12/15 15:00:00", 0.0, 1, 2, -470.0, 7, "2025/03/22 14:59:59", 10026);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 133002, 2002, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 6.15, "グレイス", "2024/12/15 15:00:00", 0.0, 2, 1, -470.0, 7, "2025/03/22 14:59:59", 10027);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 133102, 2002, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 4.28, "ヴァイオレット", "2024/12/15 15:00:00", 0.0, 1, 6, -470.0, 7, "2025/03/22 14:59:59", 10028);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 133102, 2002, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, "ヴァイオレット", "2024/12/15 15:00:00", 0.0, 2, 1, -470.0, 7, "2025/03/22 14:59:59", 10029);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 136902, 2002, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 5.53, "ルルィ", "2025/03/15 15:00:00", 0.0, 1, 2, -470.0, 8, "2025/06/23 14:59:59", 10030);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 136902, 2002, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 6.05, "ルルィ", "2025/03/15 15:00:00", 0.0, 2, 9, -470.0, 8, "2025/06/23 14:59:59", 10031);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 137001, 2002, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, "デュラン", "2025/03/15 15:00:00", 0.0, 1, 2, -470.0, 8, "2025/06/23 14:59:59", 10032);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 137001, 2002, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, "デュラン", "2025/03/15 15:00:00", 0.0, 2, 2, -470.0, 8, "2025/06/23 14:59:59", 10033);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 135902, 2002, "おう\n好きなもん持ってきな", 0.0, "サツキ", "2025/06/16 15:00:00", 0.0, 1, 2, -470.0, 9, "2025/09/23 14:59:59", 10034);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 135902, 2002, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 4.935, "サツキ", "2025/06/16 15:00:00", 0.0, 2, 1, -470.0, 9, "2025/09/23 14:59:59", 10035);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 135802, 2002, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 7.441, "ユキノ", "2025/06/16 15:00:00", 0.0, 1, 2, -470.0, 9, "2025/09/23 14:59:59", 10036);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 135802, 2002, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, "ユキノ", "2025/06/16 15:00:00", 0.0, 2, 7, -470.0, 9, "2025/09/23 14:59:59", 10037);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 130901, 2002, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2.295, "クルル", "2025/09/16 15:00:00", 0.0, 1, 2, -470.0, 10, "2025/12/22 14:59:59", 10038);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 130901, 2002, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 6.281, "クルル", "2025/09/16 15:00:00", 0.0, 2, 1, -470.0, 10, "2025/12/22 14:59:59", 10039);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 137701, 2002, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 5.549, "ヴォルガーノ", "2025/09/16 15:00:00", 0.0, 1, 2, -470.0, 10, "2025/12/22 14:59:59", 10040);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 137701, 2002, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2.64, "ヴォルガーノ", "2025/09/16 15:00:00", 0.0, 2, 3, -470.0, 10, "2025/12/22 14:59:59", 10041);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 132801, 2002, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 7.642, "ライラエル", "2025/12/15 15:00:00", 0.0, 1, 7, -470.0, 11, "2026/03/23 11:59:59", 10042);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 132802, 2002, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, "ライラエル", "2025/12/15 15:00:00", 0.0, 2, 1, -470.0, 11, "2026/03/23 11:59:59", 10043);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 134502, 2002, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, "クローチェ", "2025/12/15 15:00:00", 0.0, 1, 1, -470.0, 11, "2026/03/23 11:59:59", 10044);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 134501, 2002, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 3.72, "クローチェ", "2025/12/15 15:00:00", 0.0, 2, 2, -470.0, 11, "2026/03/23 11:59:59", 10045);
